val scheduledTransactions = getScheduledTransactions()
val rentTransaction = scheduledTransactions.map { txs =>
  txs.find(_.subject.toLowerCase.contains("rent"))
}
val rentDetails = rentTransaction.map { optTx =>
  optTx.map { tx =>
    s"Found rent transaction: id=${tx.id}, recipient=${tx.recipient}, amount=${tx.amount}, date=${tx.date}, recurring=${tx.recurring}"
  }.getOrElse("No scheduled transaction for rent found.")
}
displaySecurely(rentDetails)

